import{_ as a,o as e,c as n,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),r={name:"guide/introduction.md"};function i(o,t,l,d,c,p){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>Rusty Rules Referee (R3)</strong> is a high-performance game server administration bot written in Rust. Inspired by <a href="https://www.bigbrotherbot.net/" target="_blank" rel="noreferrer">Big Brother Bot</a>, R3 monitors your Urban Terror 4.3 server in real-time — enforcing rules automatically and providing admin commands for server management.</p><h2 id="what-does-r3-do" tabindex="-1">What Does R3 Do? <a class="header-anchor" href="#what-does-r3-do" aria-label="Permalink to &quot;What Does R3 Do?&quot;">​</a></h2><p>R3 connects to your game server by tailing its log file and communicating via RCON. It:</p><ul><li><strong>Enforces rules automatically</strong> — offensive language filtering, anti-spam, team kill limits, spawn kill detection, AFK kicking, and more</li><li><strong>Provides admin commands</strong> — <code>!kick</code>, <code>!ban</code>, <code>!warn</code>, <code>!tempban</code>, team management, and dozens more</li><li><strong>Tracks statistics</strong> — kill/death ratios, XLR skill ratings, weapon stats, map stats, and leaderboards</li><li><strong>Offers a web dashboard</strong> — live scoreboard, chat monitoring, RCON console, player management, and audit logging</li></ul><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>30 Plugins</strong></td><td>Moderation, statistics, anti-abuse, chat logging, server management</td></tr><tr><td><strong>Plugin System</strong></td><td>Easy-to-implement <code>Plugin</code> trait for custom extensions</td></tr><tr><td><strong>Dual Database</strong></td><td>SQLite for simplicity, MySQL for scale</td></tr><tr><td><strong>RCON Integration</strong></td><td>Full UDP RCON client for the Quake 3 engine</td></tr><tr><td><strong>Real-Time Log Tailing</strong></td><td>Async file tailer with log rotation detection</td></tr><tr><td><strong>XLRstats</strong></td><td>Extended player statistics with ELO-based skill tracking</td></tr><tr><td><strong>Web Dashboard</strong></td><td>SvelteKit admin panel with live data via WebSocket</td></tr><tr><td><strong>Configurable</strong></td><td>TOML-based configuration with per-plugin settings</td></tr></tbody></table><h2 id="supported-games" tabindex="-1">Supported Games <a class="header-anchor" href="#supported-games" aria-label="Permalink to &quot;Supported Games&quot;">​</a></h2><ul><li><strong>Urban Terror 4.3</strong> (Quake 3 engine, UDP RCON)</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐    ┌──────────────┐    ┌───────────────┐</span></span>
<span class="line"><span>│  Game Server     │───▶│  Log Tailer  │───▶│  Log Parser   │</span></span>
<span class="line"><span>│  (Urban Terror)  │    │  (async)     │    │  (UrT 4.3)    │</span></span>
<span class="line"><span>└─────────────────┘    └──────────────┘    └───────┬───────┘</span></span>
<span class="line"><span>                                                    │</span></span>
<span class="line"><span>                                                    ▼</span></span>
<span class="line"><span>┌─────────────────┐    ┌──────────────┐    ┌───────────────┐</span></span>
<span class="line"><span>│  RCON Client    │◀───│  Plugins     │◀───│  Event System │</span></span>
<span class="line"><span>│  (UDP)          │    │  (30 total)  │    │  (60+ events) │</span></span>
<span class="line"><span>└─────────────────┘    └──────────────┘    └───────────────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>                       ┌──────────────┐</span></span>
<span class="line"><span>                       │  Database    │</span></span>
<span class="line"><span>                       │  (SQLite/    │</span></span>
<span class="line"><span>                       │   MySQL)     │</span></span>
<span class="line"><span>                       └──────────────┘</span></span></code></pre></div><ol><li>The <strong>Log Tailer</strong> continuously reads new lines from the game server&#39;s log file</li><li>The <strong>Parser</strong> converts log lines into typed events (kills, chat, connections, etc.)</li><li>The <strong>Event System</strong> dispatches events to all enabled plugins</li><li><strong>Plugins</strong> react by issuing RCON commands, updating the database, or both</li><li>The <strong>RCON Client</strong> sends commands back to the game server</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/guide/installation.html">Installation</a> — Build R3 from source</li><li><a href="/guide/quick-start.html">Quick Start</a> — Get R3 running on your server</li><li><a href="/guide/configuration.html">Configuration</a> — Full configuration reference</li><li><a href="/plugins/">Plugins</a> — Learn about all 30 plugins</li></ul>`,14)])])}const h=a(r,[["render",i]]);export{u as __pageData,h as default};
